SIGNS = [
    {"no": 1, "title": "姜公封神", "grade": "上上", "poem": "灵签求得第一枝\n龙虎风云际会时\n一旦凌霄扬自乐\n任君来往赴瑶池", "story": "\"姜公封神\"的典故源自中国商周时期的民间传说，主要流传于中原地区，后成为道教文化的重要组成部分。故事背景为商朝末年，姜子牙（姜太公）辅佐周武王伐纣，建立周朝。在"},
    {"no": 2, "title": "王道真误入桃源", "grade": "中平", "poem": "枯木逢春尽发新\n清香秀色满园林\n行人勿谓春光晚\n更有红桃倚碧云", "story": "\"王道真误入桃源\"是一个流传于中国民间的传说，主要源自道教文化和隐逸思想，广泛传播于江南地区。故事讲述了一位名叫王道真的书生，因厌倦世俗纷扰，独自入山寻幽探胜。"},
    {"no": 3, "title": "鲁班训迪", "grade": "中吉", "poem": "牛山之木皆常美\n独惜斧工尽伐他\n大器大材无足用\n规矩不准怎为槎", "story": "\"鲁班训迪\"是中国古代著名的工匠鲁班（春秋时期鲁国人，约公元前507年—前444年）的传说故事之一。鲁班被尊为中国木匠的祖师，他的技艺精湛，发明了许多工具和建筑"},
    {"no": 4, "title": "董永遇仙", "grade": "中吉", "poem": "调雏紫燕正穿梭\n来去全凭口舌多\n君汝若能多积德\n他日生子必登科", "story": "“董永遇仙”是中国著名的民间传说，主要流传于湖北、山东、江苏等地，尤其在湖北孝感地区广为传播。故事背景设定在汉代，主人公董永是东汉时期的一位贫苦农民，因家境贫寒"},
    {"no": 5, "title": "韩夫人惜花", "grade": "中平", "poem": "东园昨夜狂风急\n万紫千红亦尽倾\n幸有惜花人早起\n培回根本复栽生", "story": "“韩夫人惜花”是唐代的一个历史典故，出自唐代诗人韩愈的家族传说。韩愈的夫人卢氏（一说为韩愈的妹妹）因爱惜花草而闻名。据传，韩愈家中有一片花园，种满了各种花卉。某"},
    {"no": 6, "title": "王羲之爱鹅", "grade": "中吉", "poem": "白鹅湖上泛清波\n洗砚濡毫意若何\n留得兰亭真迹在\n千秋万世仰羲之", "story": "王羲之爱鹅的典故：这里需要补充具体典故故事。"},
    {"no": 7, "title": "吕祖赠桃", "grade": "上吉", "poem": "仙桃一枚赐尔尝\n延年益寿保安康\n更兼智慧添福禄\n积善之家庆有余", "story": "\"吕祖赠桃\"是源自中国民间的一个道教传说，主要流传于华北地区，与道教八仙之一的吕洞宾（吕祖）有关。传说吕洞宾是唐朝时期的道士，生于公元796年，修道成仙后常以济"},
    {"no": 8, "title": "裴度还带", "grade": "上吉", "poem": "当年落魄受艰辛\n忽睹蓝袍改旧身\n今日方知天道近\n功名富贵不由人", "story": "“裴度还带”是唐代的一个著名典故，讲述的是唐朝宰相裴度早年的一段经历。裴度（765年－839年），字中立，唐代中后期著名的政治家、文学家，历经唐德宗、顺宗、宪宗"},
    {"no": 9, "title": "宋太祖陈桥兵变", "grade": "上吉", "poem": "黄袍初着体\n四海尽归心\n八百年前定\n功成自有因", "story": "“宋太祖陈桥兵变”是发生在五代十国末期的重要历史事件，标志着宋朝的建立。公元960年，后周大将赵匡胤奉命率军北上抵御契丹和北汉的联合进攻。军队行至陈桥驿（今河南"},
    {"no": 10, "title": "苏秦不第", "grade": "中平", "poem": "檐前鹊噪喜声频\n好事应须问主人\n到底不如归去好\n免教流落在风尘", "story": "\"苏秦不第\"是战国时期的历史典故。苏秦（约前340年－前284年），字季子，战国时期著名的纵横家。他出身贫寒，早年曾游说各国，但屡遭失败。据《史记·苏秦列传》记"},
    {"no": 11, "title": "刘秀兴汉", "grade": "上吉", "poem": "真龙出现应天时\n九五飞龙利见机\n指日太平登大宝\n万方黎庶仰皇威", "story": "\"刘秀兴汉\"是东汉初年的历史典故。刘秀（公元前5年－公元57年），字文叔，是东汉的开国皇帝，谥号光武帝。西汉末年，王莽篡位建立新朝，导致天下大乱。刘秀作为汉室宗"},
    {"no": 12, "title": "太白捞月", "grade": "下下", "poem": "蜃楼海市幻无边\n万丈深渊实可怜\n错认水中有月影\n翻身跳落丧黄泉", "story": "“太白捞月”是中国唐代的一个著名民间传说，与诗人李白（字太白）相关。据传，李白在唐玄宗天宝年间（742-756年）因仕途失意，常借酒消愁。某夜，李白醉酒后行至江"},
    {"no": 13, "title": "孟浩然寻梅", "grade": "中吉", "poem": "踏雪寻梅莫惮寒\n清香扑鼻满林间\n相逢共醉三杯酒\n不负平生一片心", "story": "“孟浩然寻梅”是唐代诗人孟浩然的一个历史典故，反映了其隐逸生活和文人雅趣。孟浩然（689—740年），唐代著名山水田园诗人，生活在盛唐时期，以隐逸高洁著称。他一"},
    {"no": 14, "title": "东坡归隐", "grade": "中平", "poem": "归去来兮仕宦休\n陶潜解印乐悠悠\n田园将芜胡不返\n采菊东篱万事幽", "story": "“东坡归隐”是北宋时期著名文学家苏轼（号东坡居士）的历史典故。苏轼因“乌台诗案”被贬黄州（今湖北黄冈），在此期间，他逐渐看淡仕途，向往归隐田园的生活。元丰三年（"},
    {"no": 15, "title": "明皇游月殿", "grade": "上吉", "poem": "明月当空照九州\n广寒宫殿任遨游\n霓裳舞罢琼浆饮\n忘却人间万种愁", "story": "\"明皇游月殿\"是中国唐代的一个著名传说，与唐玄宗（明皇）和杨贵妃的爱情故事密切相关。唐玄宗（685-762年）是唐朝的第七位皇帝，他在位期间开创了开元盛世，但也"},
    {"no": 16, "title": "牧童跨犊", "grade": "中吉", "poem": "短笛无腔信口吹\n骑牛迤逦过前溪\n夕阳芳草天然趣\n绿水青山自在宜", "story": "“牧童跨犊”是中国古代常见的田园生活意象，常出现在诗词和绘画中，象征着自然、纯朴与自在的生活情趣。这一典故并非特指某一历史人物或具体事件，而是源于中国古代农耕文"},
    {"no": 17, "title": "庄子鼓盆", "grade": "下下", "poem": "漆园傲吏最逍遥\n鼓盆而歌万事抛\n堪叹人生如幻梦\n庄周蝴蝶两无聊", "story": "\"庄子鼓盆\"的典故出自战国时期道家代表人物庄子的故事。庄子（约前369年－前286年），名周，宋国蒙（今河南商丘）人，是道家学派的重要代表人物之一。\n\n据《庄子"},
    {"no": 18, "title": "曹国舅遇仙", "grade": "中吉", "poem": "富贵场中一散仙\n金丹点化脱尘缘\n功名富贵皆抛却\n跨鹤乘鸾上九天", "story": "\"曹国舅遇仙\"是源自中国宋代的民间传说，主要流传于中原地区，反映了道教文化中追求超脱世俗、得道成仙的思想。\n\n曹国舅，本名曹佾，是北宋仁宗时期的国舅，因其姐姐为"},
    {"no": 19, "title": "伏羲画卦", "grade": "上吉", "poem": "太极初分判\n阴阳造化机\n先天开妙理\n八卦显玄微", "story": "\"伏羲画卦\"是中国古代著名的神话传说，主要流传于黄河流域的中原地区，与中华文明的起源密切相关。伏羲是上古时期三皇之一，相传生活在距今约5000年前的原始社会末期"},
    {"no": 20, "title": "严子陵钓台", "grade": "中平", "poem": "七里滩头一钓翁\n富春山色画图中\n微躯愿托烟波里\n不羡人间万户封", "story": "\"严子陵钓台\"的典故与东汉隐士严光（字子陵）有关。严光是东汉初年人，与光武帝刘秀是同学，两人关系密切。刘秀登基后，多次征召严光入朝为官，但严光淡泊名利，不愿出仕"},
    {"no": 21, "title": "武则天赏花", "grade": "中平", "poem": "看花须待上林春\n莫待无花空折枝\n富贵荣华终有数\n劝君惜取少年时", "story": "“武则天赏花”的典故出自唐代，与女皇武则天有关。据《太平广记》记载，武则天在位期间（690年—705年），曾于冬季下令让百花开放，以显示其威权。传说武则天在寒冬"},
    {"no": 22, "title": "李太白醉酒", "grade": "中吉", "poem": "醉卧长安市上眠\n君王呼召不上船\n自称臣是酒中仙\n千古风流一谪仙", "story": "“李太白醉酒”是唐代著名诗人李白的典故，流传于中国各地，尤其在文人墨客中广为传颂。李白（701年－762年），字太白，号青莲居士，是唐代最负盛名的浪漫主义诗人，"},
    {"no": 23, "title": "张骞泛槎", "grade": "上吉", "poem": "乘槎直上斗牛宫\n万里银河一苇通\n若问前程君记取\n青云有路自能逢", "story": "\"张骞泛槎\"是源自中国古代的一个民间传说，主要流传于中国中原地区。传说中，张骞是西汉时期著名的外交家和探险家，汉武帝时期（公元前141年—公元前87年）被派遣出"},
    {"no": 24, "title": "司马相如题桥", "grade": "中吉", "poem": "男儿立志出乡关\n誓不功成不复还\n埋骨何须桑梓地\n人间无处不青山", "story": "“司马相如题桥”是西汉时期的历史典故，出自《史记·司马相如列传》。司马相如是西汉著名的文学家，字长卿，蜀郡成都人。他年轻时家境贫寒，但才华横溢，立志功成名就。传"},
    {"no": 25, "title": "朱买臣分妻", "grade": "下下", "poem": "贫贱夫妻百事哀\n锦衣还乡事可哀\n马前泼水难收拾\n覆水重收总不该", "story": "“朱买臣分妻”是中国汉代的一个历史典故，出自《汉书·朱买臣传》。朱买臣是西汉时期会稽郡吴县（今江苏苏州）人，家境贫寒，早年以砍柴为生。他的妻子因无法忍受贫困生活"},
    {"no": 26, "title": "白居易叹花", "grade": "中平", "poem": "芳菲过尽已成尘\n密叶繁枝绿渐匀\n唯有青青松柏色\n岁寒方见后凋心", "story": "\"白居易叹花\"的典故源自唐代著名诗人白居易（772-846年）。白居易是唐代中期的文学大家，以诗歌反映社会现实和表达个人情感著称。这一典故与他的诗《叹花》相呼应"},
    {"no": 27, "title": "范蠡归湖", "grade": "上吉", "poem": "鸟尽弓藏理自然\n五湖烟水好行船\n劝君莫恋功名事\n跳出樊笼便是仙", "story": "\"范蠡归湖\"是春秋时期的历史典故。范蠡是越国大夫，辅佐越王勾践灭吴复国后，深知\"鸟尽弓藏，兔死狗烹\"的道理，认为功成身退乃明智之举。他辞去官职，携西施泛舟五湖，"},
    {"no": 28, "title": "吕蒙正守困", "grade": "中平", "poem": "破窑风雪夜漫漫\n箪食瓢饮亦自安\n他日若遂凌云志\n方知天道本循环", "story": "\"吕蒙正守困\"是北宋时期的历史典故。吕蒙正（946-1011），字圣功，河南洛阳人，北宋初年著名政治家，官至宰相。他出身贫寒，年轻时家境困苦，曾在破窑中居住，过"},
    {"no": 29, "title": "夷齐让国", "grade": "中吉", "poem": "孤竹君亡二子贤\n弟兄让国各逃禅\n首阳山下薇蕨老\n留得清风万古传", "story": "“夷齐让国”是中国历史上著名的典故，出自商朝末年，涉及孤竹国的两位王子伯夷和叔齐。孤竹国是商朝的一个诸侯国，位于今河北卢龙一带。孤竹君（孤竹国的国君）去世后，按"},
    {"no": 30, "title": "孟姜女寻夫", "grade": "下下", "poem": "杞梁城崩哭断肠\n寒衣送远路茫茫\n精诚感动天垂泪\n化作涛声震海疆", "story": "“孟姜女寻夫”是中国著名的民间传说，流传于中国北方地区，尤其是河北、山东一带。故事发生在秦朝时期，背景是秦始皇修筑长城。传说孟姜女的丈夫杞梁（或作范喜良）被征去"},
    {"no": 31, "title": "达摩面壁", "grade": "中平", "poem": "九年面壁悟真诠\n一苇渡江法界宽\n心若明镜台不拭\n本来无一物可参", "story": "\"达摩面壁\"是中国佛教禅宗的重要典故，源自南北朝时期的印度高僧菩提达摩。达摩是禅宗第二十八祖，也是中国禅宗的初祖。他于南朝梁武帝时期（约520年）来到中国，传播"},
    {"no": 32, "title": "苏武牧羊", "grade": "中吉", "poem": "北海羁留十九秋\n餐毡啮雪气吞牛\n鸿雁传书终有信\n忠贞千古姓名留", "story": "\"苏武牧羊\"是西汉时期的历史典故。苏武（前140年－前60年），字子卿，杜陵（今陕西西安东南）人。汉武帝天汉元年（前100年），苏武奉命以中郎将持节出使匈奴，被"},
    {"no": 33, "title": "庄子梦蝶", "grade": "中平", "poem": "栩栩蘧蘧幻里真\n觉来谁是梦中身\n此身若问归何处\n蝶我两忘方悟神", "story": "\"庄子梦蝶\"是中国战国时期著名哲学家庄子的一个著名典故，出自《庄子·齐物论》。庄子（约前369年－前286年），名周，宋国蒙（今河南商丘）人，是道家学派的重要代"},
    {"no": 34, "title": "萧何追韩信", "grade": "上吉", "poem": "月下追贤事可师\n兴刘灭楚赖雄姿\n若非萧相殷勤意\n哪有汉家四百年", "story": "“萧何追韩信”是西汉初年的历史典故，发生在秦末汉初的动荡时期。韩信原为项羽部下，因不受重用而投奔刘邦，但仍未得到重视，遂决定离开。刘邦的丞相萧何深知韩信的才能，"},
    {"no": 35, "title": "王昭君和番", "grade": "下下", "poem": "琵琶马上怨声悲\n青冢黄昏草色萋\n红颜自古多薄命\n莫怨丹青画师欺", "story": "“王昭君和番”是汉代著名的历史典故。王昭君，名嫱，字昭君，西汉元帝时期的宫女。据《汉书》记载，汉元帝为安抚匈奴，决定以和亲政策巩固边疆和平。当时，匈奴单于呼韩邪"},
    {"no": 36, "title": "陶渊明赏菊", "grade": "中吉", "poem": "采菊东篱下\n悠然见南山\n此中有真意\n欲辨已忘言", "story": "“陶渊明赏菊”的典故源自东晋时期著名诗人陶渊明（365年—427年），他是中国文学史上田园诗派的代表人物。陶渊明因不满官场腐败，辞去彭泽县令一职，归隐田园，过着"},
    {"no": 37, "title": "李靖遇仙", "grade": "上吉", "poem": "虬髯客传奇事传\n风尘三侠义薄天\n他年若遂凌云志\n海外称王亦自然", "story": "“李靖遇仙”是唐代流传的民间传说，主要讲述李靖在未成名时与神仙相遇的故事。李靖是唐朝开国名将，字药师，生于隋末唐初。传说他在年轻时曾在山中遇到一位仙人，仙人传授"},
    {"no": 38, "title": "韩湘子度叔", "grade": "中吉", "poem": "蓝关雪拥马难前\n云横秦岭家何处\n方知叔父修行晚\n湘子空中现偈言", "story": "“韩湘子度叔”是中国民间广为流传的道教传说，主要讲述八仙之一的韩湘子度化其叔父韩愈的故事。韩愈是唐代著名文学家、思想家，曾任监察御史等职，因谏迎佛骨被贬潮州。传"},
    {"no": 39, "title": "刘晨阮肇入天台", "grade": "中平", "poem": "采药深山遇仙缘\n胡麻饭罢不知年\n归来城郭皆非旧\n方信壶中别有天", "story": "\"刘晨阮肇入天台\"是流传于中国浙江天台山地区的民间传说，最早见于南朝刘义庆的《幽明录》。故事发生在东汉时期，讲述了刘晨和阮肇两位采药人入天台山采药，偶遇仙女的奇"},
    {"no": 40, "title": "马援征交趾", "grade": "中吉", "poem": "铜柱标功壮士歌\n裹尸马革志如何\n老当益壮心犹烈\n何必封侯万户多", "story": "“马援征交趾”是东汉时期的历史典故。马援（前14年－49年），字文渊，扶风茂陵（今陕西兴平）人，东汉初年著名将领。东汉建武十七年（41年），交趾郡（今越南北部）"},
    {"no": 41, "title": "陶侃移舟", "grade": "中平", "poem": "陶公机智避灾星\n舟藏密室保家声\n临危不乱真豪杰\n留得青山薪火承", "story": "“陶侃移舟”是东晋时期的历史典故，出自《晋书·陶侃传》。陶侃（259年－334年），字士行，东晋名将，以清廉、勤勉和机智著称。典故发生在东晋初年，陶侃任荆州刺史"},
    {"no": 42, "title": "孔子击磬", "grade": "中吉", "poem": "荷篑过门识雅音\n知音难遇古犹今\n磬声自有通天道\n何必区区求世人", "story": "“孔子击磬”是春秋时期的一个历史典故，记载于《论语·宪问》。孔子（前551年－前479年）是春秋末期鲁国的思想家、教育家，儒家学派的创始人。当时，孔子周游列国，"},
    {"no": 43, "title": "玄奘取经", "grade": "上吉", "poem": "万里西行求法真\n八十一难炼金身\n取得真经回东土\n大乘佛法度迷津", "story": "“玄奘取经”是中国唐代著名的历史事件，也是广泛流传的民间传说。玄奘（602年－664年），俗姓陈，名祎，洛阳缑氏（今河南偃师）人，是唐代著名的佛教高僧、翻译家和"},
    {"no": 44, "title": "王母蟠桃", "grade": "上上", "poem": "瑶池阿母绮窗开\n三度偷桃小儿孩\n若问长生何术得\n心无恶念自仙胎", "story": "\"王母蟠桃\"是中国古代神话传说中的重要典故，主要流传于中原地区，与道教文化密切相关。据《山海经》和《汉武帝内传》等古籍记载，西王母居住在昆仑山瑶池，园中种有蟠桃"},
    {"no": 45, "title": "舜耕历山", "grade": "上吉", "poem": "大孝格天感象耕\n历山雷泽万民钦\n纵然身处卑微地\n终有尧天舜日临", "story": "“舜耕历山”是中国古代著名的历史典故，源自上古时期的传说，主要流传于中国黄河流域，尤其是山东、山西等地。舜，名重华，是中国上古五帝之一，生活在约公元前23世纪至"},
    {"no": 46, "title": "嫦娥奔月", "grade": "下下", "poem": "偷得灵药离尘寰\n广寒寂寞锁朱颜\n碧海青天夜夜心\n不如人间共婵娟", "story": "“嫦娥奔月”是中国古代著名的民间传说，流传于全国各地，尤其在汉族文化中影响深远。传说源于上古时期，与后羿射日的故事密切相关。后羿是尧帝时期的英雄，因射下九日拯救"},
    {"no": 47, "title": "梁鸿配孟光", "grade": "中吉", "poem": "荆钗布裙又何妨\n举案齐眉敬如宾\n自古姻缘天注定\n德配贤良福自生", "story": "“梁鸿配孟光”是东汉时期的历史典故，出自《后汉书·逸民传》。梁鸿，字伯鸾，东汉初年扶风平陵（今陕西咸阳）人，是一位著名的隐士和学者。孟光是梁鸿的妻子，以贤德著称"},
    {"no": 48, "title": "韩信问路", "grade": "中平", "poem": "迷途问道遇樵夫\n指点迷津出险途\n莫道草野无贤士\n解人常在山水隅", "story": "“韩信问路”是中国古代的一个民间传说，流传于中国各地，尤其在江淮地区广为流传。故事发生在秦末汉初，韩信是西汉开国名将，早年因家境贫寒，曾四处漂泊。传说韩信在投奔"},
    {"no": 49, "title": "张良遇仙", "grade": "上吉", "poem": "圯桥进履得奇书\n辅汉灭秦展宏图\n功成身退从赤松\n方是人间大丈夫", "story": "“张良遇仙”是汉朝时期的历史典故，讲述了张良在圯桥遇到黄石公并得到《太公兵法》的故事。张良是西汉开国功臣，早年因刺杀秦始皇失败而隐居。一次，他在下邳（今江苏邳州"},
    {"no": 50, "title": "范仲淹断齑", "grade": "中吉", "poem": "划粥断齑苦读书\n先忧后乐圣贤模\n寒窗莫道艰辛甚\n朱衣终有点头时", "story": "“范仲淹断齑”是北宋时期的历史典故，出自宋代文学家范仲淹的早年生活经历。范仲淹（989年—1052年），字希文，北宋政治家、文学家，以“先天下之忧而忧，后天下之"},
    {"no": 51, "title": "刘备招亲", "grade": "中平", "poem": "甘露寺中巧计成\n周郎妙算总虚名\n赔了夫人又折兵\n江山依旧属汉庭", "story": "\"刘备招亲\"是三国时期的历史典故，发生在东汉末年（约公元208年）。当时，刘备与孙权结盟对抗曹操，孙权为了巩固联盟，提出将妹妹孙尚香嫁给刘备。然而，这实际上是周"},
    {"no": 52, "title": "李白醉草", "grade": "中吉", "poem": "醉写蛮书惊四筵\n脱靴研墨逞诗篇\n若非天子金门诏\n谁识谪仙文曲星", "story": "“李白醉草”是唐代著名诗人李白的典故，出自《新唐书·李白传》。唐玄宗天宝年间，李白因才华横溢被召入长安，供奉翰林。一次，唐玄宗命李白起草诏书，李白当时已醉酒，但"},
    {"no": 53, "title": "诸葛禳星", "grade": "下下", "poem": "五丈原头星陨坠\n汉祚将倾不可回\n尽瘁鞠躬终有数\n天命难违究可哀", "story": "“诸葛禳星”是三国时期的历史典故，与蜀汉丞相诸葛亮密切相关。据《三国志》和《三国演义》记载，诸葛亮在五丈原（今陕西宝鸡境内）与魏军对峙时，因积劳成疾，自知命不久"},
    {"no": 54, "title": "羲之换鹅", "grade": "中吉", "poem": "黄庭一卷换白鹅\n墨池尽染兰亭波\n雅趣自非常人识\n留得千秋书圣名", "story": "\"羲之换鹅\"是东晋时期著名的书法家王羲之的典故。王羲之（303-361年），字逸少，东晋琅琊临沂（今山东临沂）人，被誉为\"书圣\"。据《晋书·王羲之传》记载，王羲"},
    {"no": 55, "title": "郭子仪拜寿", "grade": "上吉", "poem": "七子八婿满床笏\n富贵寿考古今无\n积善之家有余庆\n汾阳王府福禄殊", "story": "“郭子仪拜寿”是唐代著名的历史典故，发生在唐朝中期。郭子仪是唐朝名将，因平定安史之乱、保卫国家有功，被封为汾阳王，享有极高的地位和声望。他一生功勋卓著，且为人宽"},
    {"no": 56, "title": "伯牙碎琴", "grade": "下下", "poem": "摔碎瑶琴凤尾寒\n子期不在对谁弹\n春风满面皆朋友\n欲觅知音难上难", "story": "\"伯牙碎琴\"是中国古代著名的知音典故，出自《列子·汤问》，发生在春秋时期。故事讲述了琴师伯牙与樵夫钟子期之间的深厚友谊。\n\n伯牙是春秋时期著名的琴师，技艺高超。"},
    {"no": 57, "title": "霸王别姬", "grade": "下下", "poem": "力拔山兮气盖世\n时不利兮骓不逝\n虞姬虞姬奈若何\n乌江自刎空余志", "story": "“霸王别姬”是中国历史上著名的典故，发生在秦末汉初的楚汉争霸时期。项羽（西楚霸王）与刘邦争夺天下，最终在垓下之战中陷入绝境。项羽被汉军重重包围，兵少粮尽，夜晚听"},
    {"no": 58, "title": "文姬归汉", "grade": "中平", "poem": "胡笳十八拍声悲\n万里归心日夜驰\n抛儿别女肝肠断\n独留青冢向天涯", "story": "“文姬归汉”是东汉末年著名的历史典故，讲述的是才女蔡文姬从匈奴归汉的故事。蔡文姬，名琰，字文姬，是东汉著名文学家蔡邕之女。她博学多才，精通音律，但生逢乱世。东汉"},
    {"no": 59, "title": "狄青降龙", "grade": "上吉", "poem": "面涅将军气如虹\n昆仑关前建奇功\n自古英雄出草莽\n岂以出身论豪雄", "story": "“狄青降龙”是中国北宋时期的一个历史典故，与名将狄青有关。狄青（1008年—1057年），字汉臣，北宋著名军事将领，出身寒微，因面有刺青（面涅）而被称为“面涅将"},
    {"no": 60, "title": "钟馗捉鬼", "grade": "中吉", "poem": "进士蒙冤触阶亡\n化身鬼王镇邪妄\n铁面无私扫妖氛\n万家供奉保安康", "story": "“钟馗捉鬼”是中国民间广为流传的传说，主要讲述唐代进士钟馗的故事。据传，钟馗是唐玄宗时期（公元712-756年）的进士，才华横溢，但因相貌丑陋，殿试时被皇帝嫌弃"},
    {"no": 61, "title": "吕祖医疮", "grade": "中平", "poem": "药饵虽灵终有损\n金丹一粒可回春\n劝君早觅修真路\n莫待沉疴误此身", "story": "“吕祖医疮”是流传于中国民间的道教传说，主要与八仙之一的吕洞宾（吕祖）有关。吕洞宾是唐代著名的道教人物，被尊为全真教的祖师之一。传说中，吕洞宾不仅精通炼丹修道，"},
    {"no": 62, "title": "卞和献玉", "grade": "下下", "poem": "三献荆山泣血频\n楚王不识连城珍\n直至剖开方见宝\n可怜双足已残身", "story": "“卞和献玉”是中国战国时期的一个历史典故，流传于楚国地区（今湖北、湖南一带）。故事的主人公卞和是楚国的一位平民，他在荆山发现了一块未经雕琢的璞玉，认为其中蕴藏着"},
    {"no": 63, "title": "颜回乐道", "grade": "上吉", "poem": "一箪一瓢陋巷居\n回也不改其乐初\n贤哉德配天地久\n万古儒门圣楷模", "story": "\"颜回乐道\"是春秋时期孔子的弟子颜回的故事，出自《论语·雍也》。颜回（公元前521年—公元前481年），字子渊，鲁国人，是孔子最得意的门生之一。孔子曾称赞他：\""},
    {"no": 64, "title": "张骞乘槎", "grade": "中吉", "poem": "银汉迢迢一槎通\n牛郎织女喜相逢\n若问前程休挂虑\n鹏程万里御长风", "story": "\"张骞乘槎\"是中国古代的一个民间传说，主要流传于黄河流域和长江流域地区。这个传说与汉代著名的外交家张骞有关。\n\n张骞是西汉时期（公元前206年-公元8年）的著名"},
    {"no": 65, "title": "孔子在陈", "grade": "中平", "poem": "陈蔡绝粮七日困\n弦歌不辍志犹存\n天将大任降贤哲\n磨炼身心启后昆", "story": "“孔子在陈”的典故出自《史记·孔子世家》，发生在春秋时期。孔子周游列国时，曾带领弟子前往陈国（今河南淮阳一带）。在陈国期间，孔子遭遇了陈蔡之困。当时，陈国和蔡国"},
    {"no": 66, "title": "女娲补天", "grade": "上吉", "poem": "炼石五色补穹苍\n断鳌立极镇四方\n功盖乾坤垂万世\n母仪天下永流芳", "story": "“女娲补天”是中国古代著名的神话传说，流传于中华文化圈，尤其在汉族地区广为传颂。传说在上古时期，天地初开，水神共工与火神祝融大战，共工战败后怒撞不周山，导致天柱"},
    {"no": 67, "title": "江淹梦笔", "grade": "下下", "poem": "梦授彩笔显文才\n妙句华章信手来\n岂料晚年才思尽\n江郎有负此奇胎", "story": "“江淹梦笔”是中国南北朝时期的一个著名典故，出自南朝文学家江淹的故事。江淹（444年—505年），字文通，南朝梁代文学家，以文采斐然著称。据《南史·江淹传》记载"},
    {"no": 68, "title": "伯乐相马", "grade": "中吉", "poem": "骐骥盐车困坂行\n伯乐一顾价连城\n世间岂乏千里马\n只叹知音难遇明", "story": "“伯乐相马”是中国古代著名的典故，出自春秋战国时期。伯乐，原名孙阳，是春秋时期秦国的相马专家，因其善于识别千里马而闻名。典故的主要内容是：有一次，伯乐路过一个山"},
    {"no": 69, "title": "董狐直笔", "grade": "中平", "poem": "晋史董狐书法严\n赵盾弑君记简编\n纵然权贵难移志\n留得千秋正气篇", "story": "\"董狐直笔\"是中国春秋时期的历史典故，出自《左传·宣公二年》。董狐是晋国的史官，以秉笔直书、不畏权贵著称。当时，晋灵公昏庸无道，大臣赵盾多次劝谏无效。后来晋灵公"},
    {"no": 70, "title": "杜牧寻春", "grade": "中吉", "poem": "落魄江湖载酒行\n楚腰纤细掌中轻\n十年一觉扬州梦\n赢得青楼薄幸名", "story": "\"杜牧寻春\"是唐代诗人杜牧的一段历史典故。杜牧（803年－852年），字牧之，号樊川居士，晚唐著名诗人，与李商隐并称\"小李杜\"。\n\n据《唐才子传》记载，杜牧在唐"},
    {"no": 71, "title": "管宁割席", "grade": "中平", "poem": "割席分坐志不同\n道殊难与小人同\n择友当须慎始终\n近朱近墨效验通", "story": "“管宁割席”是中国三国时期的历史典故，出自《世说新语·德行》。故事发生在东汉末年，管宁和华歆是两位著名的学者，他们年轻时曾一起读书，关系密切。一天，两人在园中锄"},
    {"no": 72, "title": "鲍叔荐管仲", "grade": "上吉", "poem": "知人善荐鲍叔贤\n管仲功成赖引牵\n千古交情谁似此\n黄金台上姓名镌", "story": "“鲍叔荐管仲”是春秋时期的历史典故，发生在齐国。鲍叔牙和管仲是好友，早年曾一起经商，鲍叔牙深知管仲的才能。后来，鲍叔牙辅佐公子小白（即齐桓公），管仲则辅佐公子纠"},
    {"no": 73, "title": "王勃滕王阁序", "grade": "上吉", "poem": "秋水长天共一色\n落霞孤鹜齐飞扬\n文光直射斗牛际\n童子何知也擅场", "story": "《滕王阁序》是唐代文学家王勃创作的一篇骈文，作于唐高宗上元二年（675年）。当时，洪州都督阎伯屿重修滕王阁，于重阳节在阁上大宴宾客，王勃受邀参加。席间，阎伯屿有"},
    {"no": 74, "title": "张良博浪椎", "grade": "中吉", "poem": "博浪沙中奋铁椎\n误中副车事难追\n若非圯上逢黄石\n哪得汉家四百基", "story": "\"张良博浪椎\"的典故发生在秦朝末年。张良，字子房，是汉初著名的谋士。他本是韩国贵族，因秦灭韩而心怀仇恨。公元前218年，秦始皇东巡至博浪沙（今河南原阳东南）时，"},
    {"no": 75, "title": "刘智远得岳氏", "grade": "中吉", "poem": "瓜园别妻泪涟涟\n磨房产子志益坚\n他日身登九五位\n糟糠恩义永流传", "story": "“刘智远得岳氏”是五代十国时期的历史典故，讲述了后汉开国皇帝刘知远（字智远）与妻子李氏（岳氏）的故事。刘知远出身贫寒，年轻时在太原为军卒，与李氏结为夫妻。李氏出"},
    {"no": 76, "title": "杨震却金", "grade": "上吉", "poem": "暮夜辞金四知堂\n天知地知你知我知\n廉能太守垂青史\n留得清风万古扬", "story": "\"杨震却金\"是东汉时期的一个著名典故，出自《后汉书·杨震传》。杨震（？—124年），字伯起，东汉弘农华阴（今陕西华阴）人，是东汉时期著名的清官。\n\n故事发生在杨"},
    {"no": 77, "title": "左慈戏曹", "grade": "下下", "poem": "画壁化羊戏奸雄\n欺君罔上罪难容\n仙家妙术虽玄妙\n到底难逃劫数终", "story": "“左慈戏曹”是三国时期的一个著名典故，出自《后汉书·方术传》和《三国志》等史籍。左慈是东汉末年的方士，精通道术，擅长幻化之术。曹操是当时权倾朝野的丞相，性格多疑"},
    {"no": 78, "title": "赵子龙救主", "grade": "上吉", "poem": "长坂坡前杀气腾\n单枪匹马救储君\n浑身是胆真豪杰\n青史留名赵将军", "story": "\"赵子龙救主\"是三国时期的历史典故，发生在公元208年的长坂坡之战。赵云，字子龙，是蜀汉名将。当时刘备在荆州被曹操大军追击，携百姓南逃。在长坂坡，刘备的妻儿与大"},
    {"no": 79, "title": "班超投笔", "grade": "中吉", "poem": "封侯万里志昂藏\n投笔从戎赴异疆\n三十六人平西域\n功成麟阁姓名香", "story": "\"班超投笔\"是东汉时期的历史典故。班超（32年－102年），字仲升，扶风安陵（今陕西咸阳）人，是东汉著名的军事家、外交家。班超年轻时在官府担任文书工作，但他胸怀"},
    {"no": 80, "title": "弄玉吹箫", "grade": "中平", "poem": "凤台仙侣奏鸾笙\n跨凤乘鸾上玉京\n若问姻缘何日就\n琴瑟和谐自有盟", "story": "“弄玉吹箫”是中国古代著名的民间传说，源自春秋时期，流传于中原地区，后被广泛记载于《列仙传》等古籍中。传说秦穆公之女弄玉，容貌绝美，擅长吹箫，其箫声能引来凤凰。"},
    {"no": 81, "title": "洛神凌波", "grade": "中平", "poem": "翩若惊鸿婉游龙\n凌波微步罗袜生\n君王空有陈思赋\n不及湘妃竹泪情", "story": "“洛神凌波”典故源自三国时期曹植的《洛神赋》。曹植是魏文帝曹丕之弟，才华横溢，但因政治斗争被贬。传说曹植在黄初三年（公元222年）途经洛水时，梦见洛水女神宓妃，"},
    {"no": 82, "title": "彭祖焚香", "grade": "上吉", "poem": "寿享八百世间稀\n焚香修道悟玄机\n若能寡欲清心志\n自可长生伴鹤栖", "story": "\"彭祖焚香\"的典故源自中国古代民间传说，主要流传于中原地区，与道教文化密切相关。彭祖，名铿，是上古时期尧帝的臣子，相传他活了八百岁，成为中国传统文化中长寿的象征"},
    {"no": 83, "title": "李邺侯白衣", "grade": "中吉", "poem": "白衣山人隐衡岳\n李泌功成身早退\n千古功名藏与显\n智者从来知进退", "story": "“李邺侯白衣”典故源自唐代历史人物李泌。李泌（722年－789年），字长源，唐朝中期著名政治家、谋略家，历经玄宗、肃宗、代宗、德宗四朝，因其功勋卓著，被封为邺侯"},
    {"no": 84, "title": "宋玉赋高唐", "grade": "中平", "poem": "朝云暮雨总成空\n神女襄王梦寐中\n色即是空空即色\n何须执着问穷通", "story": "\"宋玉赋高唐\"的典故出自战国时期楚国辞赋家宋玉的作品《高唐赋》。该赋描述了楚襄王与宋玉游于云梦之台，宋玉向襄王讲述了一个关于巫山神女的传说。故事中，楚怀王曾游高"},
    {"no": 85, "title": "张敞画眉", "grade": "中吉", "poem": "闺房之乐胜画眉\n风流京兆古今奇\n画眉深浅入时无\n伉俪情深自可知", "story": "\"张敞画眉\"是汉代著名的历史典故，出自《汉书·张敞传》。张敞是西汉宣帝时期的京兆尹（相当于首都长安的最高行政长官），以治理有方、政绩卓著而闻名。然而，他最为后人"},
    {"no": 86, "title": "舜帝耕田", "grade": "上吉", "poem": "大孝巍巍感动天\n象耕鸟耘助田边\n纵然历尽千般苦\n终得尧禅万代传", "story": "“舜帝耕田”是中国古代著名的历史典故，源自上古时期。舜，姓姚，名重华，是传说中的五帝之一，生活在约公元前23世纪至前22世纪的尧舜时代。舜以孝行闻名，传说他的父"},
    {"no": 87, "title": "吕后称制", "grade": "下下", "poem": "牝鸡司晨祸患生\n功臣诛戮鬼神惊\n若非平勃安刘计\n汉室江山早变更", "story": "“吕后称制”是中国西汉时期的重要历史事件。吕后，即吕雉，是汉高祖刘邦的皇后。刘邦去世后，其子汉惠帝刘盈继位，但刘盈性格软弱，朝政大权逐渐落入吕后手中。汉惠帝去世"},
    {"no": 88, "title": "李白乘舟", "grade": "中吉", "poem": "两岸猿声啼不住\n轻舟已过万重山\n顺风顺水前程快\n何惧江湖行路难", "story": "\"李白乘舟\"的典故源自唐代诗人李白的生平事迹。李白（701年－762年），字太白，号青莲居士，是唐代著名的浪漫主义诗人，被誉为\"诗仙\"。他一生热爱游历，足迹遍布"},
    {"no": 89, "title": "刘向传经", "grade": "中吉", "poem": "天禄校书苦用功\n太乙燃藜照学宫\n他年若得青云路\n万卷诗书在腹中", "story": "\"刘向传经\"的典故出自西汉时期，与刘向在天禄阁校书的故事密切相关。刘向（约前77年－前6年），字子政，西汉著名的经学家、目录学家、文学家，汉成帝时期曾任光禄大夫"},
    {"no": 90, "title": "王维隐居", "grade": "中平", "poem": "辋川别业远尘嚣\n诗佛丹青两绝超\n明月松间照清泉\n淡泊自能乐逍遥", "story": "王维是唐代著名的诗人、画家，被誉为“诗佛”。他晚年隐居在辋川别业，远离朝廷纷争，追求心灵的自由与宁静。辋川位于今陕西省蓝田县，是王维精心营造的一处山水园林，环境"},
    {"no": 91, "title": "范蠡献西施", "grade": "下下", "poem": "倾城倾国色艺精\n吴宫歌舞误朝廷\n沼吴原是佳人计\n鸟尽弓藏理自明", "story": "“范蠡献西施”是中国春秋时期的历史典故，发生在吴越争霸的背景下。范蠡是越国大夫，辅佐越王勾践复国。当时吴王夫差击败越国，勾践被迫臣服。为削弱吴国，范蠡提出“美人"},
    {"no": 92, "title": "蔡邕操琴", "grade": "中平", "poem": "焦尾琴成世所珍\n广陵散绝更无伦\n知音若遇钟期耳\n流水高山自有神", "story": "\"蔡邕操琴\"是中国东汉时期的著名典故，涉及历史人物蔡邕及其所制名琴\"焦尾琴\"。蔡邕（133年－192年），字伯喈，东汉末年著名文学家、书法家、音乐家，精通音律，"},
    {"no": 93, "title": "孙康映雪", "grade": "中吉", "poem": "家贫无油夜读书\n雪光映照字模糊\n他年若遂凌云志\n不负寒窗十载孤", "story": "“孙康映雪”是中国古代著名的勤学典故，出自晋代。孙康是晋朝人，家境贫寒，但他酷爱读书。由于家中无钱购买灯油，夜晚无法照明读书，他便利用雪地反射的月光来读书。每逢"},
    {"no": 94, "title": "刘备借荆州", "grade": "中平", "poem": "借得荆襄暂驻兵\n周郎妙计总成空\n三分天下隆中对\n鼎足峙立赖孔明", "story": "“刘备借荆州”是中国三国时期的历史典故，发生在东汉末年（约公元208年）。当时，刘备在赤壁之战后实力薄弱，急需根据地以图发展。荆州是战略要地，原由刘表统治，刘表"},
    {"no": 95, "title": "文君当垆", "grade": "中吉", "poem": "当垆卖酒不羞贫\n琴挑芳心情意真\n白头吟罢长门赋\n千古风流卓文君", "story": "“文君当垆”是中国汉代的一个历史典故，出自《史记·司马相如列传》。故事发生在西汉时期，主角是才子司马相如和才女卓文君。司马相如因家贫，曾寄居在临邛（今四川邛崃）"},
    {"no": 96, "title": "蔺相如完璧", "grade": "上吉", "poem": "秦庭抗节显英豪\n完璧归赵智谋高\n凭君三寸不烂舌\n胜过百万虎狼刀", "story": "\"蔺相如完璧\"是战国时期的历史典故，发生在公元前283年。当时，秦国强大，赵国较弱。秦昭王得知赵国有一块稀世宝玉\"和氏璧\"，便提出以十五座城池交换。赵惠文王担心"},
    {"no": 97, "title": "华佗治病", "grade": "中吉", "poem": "刮骨疗毒显神术\n麻沸散成万病除\n医者仁心传千古\n青囊妙术济世书", "story": "\"华佗治病\"的典故源自东汉末年著名医学家华佗的传奇事迹。华佗（约145年－208年），字元化，沛国谯县（今安徽亳州）人，是东汉末年著名的医学家，被后世尊为\"外科"},
    {"no": 98, "title": "管鲍分金", "grade": "上吉", "poem": "昔日管鲍为知己\n分金仁义传千古\n凡事若能依样做\n万事亨通无龃龉", "story": "“管鲍分金”是中国春秋时期的历史典故，讲述了管仲和鲍叔牙之间深厚的友谊与信任。管仲和鲍叔牙是春秋时期齐国的两位重要人物，管仲后来成为齐桓公的宰相，辅佐齐桓公成为"},
    {"no": 99, "title": "韩文公祭鳄鱼", "grade": "中平", "poem": "昔日文公治鳄患\n浩然正气动天地\n凶顽尚可德化改\n劝君修心莫迟疑", "story": "“韩文公祭鳄鱼”是唐代著名文学家、政治家韩愈（字退之，谥号文公）在潮州任刺史时的一个历史典故。韩愈因谏迎佛骨被贬潮州，于唐宪宗元和十四年（819年）到任。当时潮"},
    {"no": 100, "title": "唐太宗赏牡丹", "grade": "上上", "poem": "百花竞放春光好\n独占鳌头牡丹王\n求得此签百事吉\n福寿康宁降吉祥", "story": "\"唐太宗赏牡丹\"的典故发生在唐代，具体背景是唐太宗李世民在位期间（公元626年—649年）。唐太宗是中国历史上著名的明君，他以文治武功著称，开创了\"贞观之治\"的"},
]